      vendorBinDir,
      pathWin32.join(home, 'AppData', 'Roaming', 'npm'),
      pathWin32.join(home, 'scoop', 'shims'),
      pathWin32.join(home, '.bun', 'bin'),
      pathWin32.join(home, '.cargo', 'bin'),
      pathWin32.join(home, '.volta', 'bin')
